/**
 * mt-cli extension for GSD.
 *
 * Opt-in extension that syncs GSD lifecycle events to the Milestone Tracker
 * via mt-cli CLI calls (claim, progress, block, complete).
 *
 * Non-blocking and idempotent вҖ” sync failures never block auto-mode.
 *
 * Integration happens via hooks (execute-task, complete-task) declared in
 * extension-manifest.json. This index registers a `/mt-cli` slash command
 * for manual bootstrap and status display.
 *
 * Architecture follows the github-sync/index.js pattern.
 */
import { bootstrapSync, getSyncStatus, setDebugLog } from "./sync.js";
import { mtCliIsAvailable } from "./cli.js";

export default function (pi) {
  // Wire up the debug log function from the GSD extension host
  if (pi?.debugLog) {
    setDebugLog((channel, data) => pi.debugLog(channel, data));
  }

  pi.registerCommand("mt-cli", {
    description: "Bootstrap mt-cli sync or show sync status",
    handler: async (args, ctx) => {
      const subcommand = args.trim().toLowerCase();

      if (subcommand === "status") {
        await showStatus(ctx);
        return;
      }

      if (subcommand === "bootstrap" || subcommand === "") {
        await runBootstrap(ctx);
        return;
      }

      ctx.ui.notify("Usage: /mt-cli [bootstrap|status]", "info");
    },
  });
}

async function showStatus(ctx) {
  if (!mtCliIsAvailable()) {
    ctx.ui.notify(
      "mt-cli sync: `mt-cli` CLI not installed or not on PATH.",
      "warning",
    );
    return;
  }

  const status = getSyncStatus(ctx.cwd);
  if (!status) {
    ctx.ui.notify(
      "mt-cli sync: No sync mapping found. Run `/mt-cli bootstrap` to initialize.",
      "info",
    );
    return;
  }

  ctx.ui.notify(
    [
      `mt-cli sync: milestone=${status.milestoneId}`,
      `  Slices: ${status.slicesTotal} (${status.slicesCompleted} completed)`,
      `  Tasks: ${status.tasksTotal} total, ${status.tasksMapped} mapped, ${status.tasksUnmapped} unmapped, ${status.tasksCompleted} completed`,
      status.lastTaskSync ? `  Last sync: ${status.lastTaskSync}` : "",
    ]
      .filter(Boolean)
      .join("\n"),
    "info",
  );
}

async function runBootstrap(ctx) {
  if (!mtCliIsAvailable()) {
    ctx.ui.notify(
      "mt-cli sync: `mt-cli` CLI not installed or not on PATH.",
      "warning",
    );
    return;
  }

  ctx.ui.notify("mt-cli sync: bootstrapping...", "info");

  try {
    const counts = await bootstrapSync(ctx.cwd);

    if (counts.milestones === 0 && counts.slices === 0 && counts.tasks === 0) {
      ctx.ui.notify(
        "mt-cli sync: everything already synced (or no milestones found).",
        "info",
      );
    } else {
      ctx.ui.notify(
        `mt-cli sync: indexed ${counts.milestones} milestone(s), ${counts.slices} slice(s), ${counts.tasks} task(s).`,
        "info",
      );
    }
  } catch (err) {
    ctx.ui.notify(`mt-cli sync bootstrap failed: ${err}`, "error");
  }
}

/**
 * Core mt-cli sync engine.
 *
 * Entry point: `runMtSync()` вҖ” called from the GSD post-unit pipeline.
 * Routes to per-event sync functions based on unit type, calls mt-cli
 * via cli.js wrappers, and persists the mapping.
 *
 * All errors are caught internally вҖ” sync failures never block execution.
 *
 * Architecture follows the github-sync/sync.js pattern.
 */
import { existsSync, readdirSync } from "node:fs";
import { join } from "node:path";

import {
  mtCliIsAvailable,
  mtCliStatus,
  mtCliTasksClaim,
  mtCliTasksProgress,
  mtCliTasksBlock,
  mtCliTasksComplete,
} from "./cli.js";
import {
  loadSyncMapping,
  saveSyncMapping,
  createEmptyMapping,
  getSliceRecord,
  getTaskRecord,
  getMtTaskId,
  setSliceRecord,
  setTaskRecord,
} from "./mapping.js";

// в”Җв”Җв”Җ Debug logging shim в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// Extensions are self-contained; we can't import from ../gsd/debug-logger.js.
// When loaded by the GSD process, `pi.debugLog` is injected via the extension
// context. For standalone use / tests, we fall back to console.error.

let _debugLogFn = null;

/**
 * Set the debug log function (called by index.js on registration).
 * @param {function} fn
 */
export function setDebugLog(fn) {
  _debugLogFn = fn;
}

/**
 * Log a structured debug message.
 * @param {string} channel
 * @param {object} data
 */
function debugLog(channel, data) {
  if (_debugLogFn) {
    _debugLogFn(channel, data);
  } else {
    // Standalone / test fallback вҖ” silent unless MT_SYNC_DEBUG=1
    if (process.env.MT_SYNC_DEBUG === "1") {
      console.error(`[mt-sync] ${channel}:`, JSON.stringify(data));
    }
  }
}

// в”Җв”Җв”Җ Entry Point в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

/**
 * Main sync entry point вҖ” called from GSD post-unit pipeline.
 * Routes to the appropriate sync function based on unit type.
 *
 * @param {string} basePath - Project root path
 * @param {string} unitType - One of: plan-slice, execute-task, complete-slice, complete-task
 * @param {string} unitId - Composite ID like "M003/S05/T02"
 */
export async function runMtSync(basePath, unitType, unitId) {
  try {
    if (!mtCliIsAvailable()) {
      debugLog("mt-sync", { skip: "mt-cli not available" });
      return;
    }

    // Parse unit ID parts
    const parts = unitId.split("/");
    const [mid, sid, tid] = parts;

    // Load or init mapping
    let mapping = loadSyncMapping(basePath);
    if (!mapping) {
      mapping = createEmptyMapping(mid);
    }

    // Route by unit type
    switch (unitType) {
      case "plan-slice":
        if (mid && sid) await syncSlicePlan(basePath, mapping, mid, sid);
        break;
      case "execute-task":
      case "reactive-execute":
        if (mid && sid && tid) await syncTaskExecute(basePath, mapping, mid, sid, tid);
        break;
      case "complete-task":
        if (mid && sid && tid) await syncTaskComplete(basePath, mapping, mid, sid, tid);
        break;
      case "complete-slice":
        if (mid && sid) await syncSliceComplete(basePath, mapping, mid, sid);
        break;
      default:
        debugLog("mt-sync", { skip: "unhandled unitType", unitType, unitId });
        break;
    }

    saveSyncMapping(basePath, mapping);
  } catch (err) {
    debugLog("mt-sync", { error: String(err), unitType, unitId });
  }
}

// в”Җв”Җв”Җ Per-Event Sync Functions в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

/**
 * Sync when a slice is planned вҖ” no-op for mt-cli since it only syncs task lifecycle.
 * Records the slice in the mapping for tracking.
 */
async function syncSlicePlan(basePath, mapping, mid, sid) {
  const existing = getSliceRecord(mapping, mid, sid);
  if (existing) return;

  setSliceRecord(mapping, mid, sid, {
    syncedAt: new Date().toISOString(),
    state: "planned",
  });

  debugLog("mt-sync", { phase: "slice-plan", mid, sid });
}

/**
 * Sync when a task starts execution вҖ” claim the task in Milestone Tracker.
 */
async function syncTaskExecute(basePath, mapping, mid, sid, tid) {
  const existing = getTaskRecord(mapping, mid, sid, tid);
  // Only claim once
  if (existing?.state === "claimed" || existing?.state === "in_progress") return;

  const mtTaskId = getMtTaskId(mapping, mid, sid, tid);

  // If we don't have a mapping, we can't sync вҖ” skip silently
  if (!mtTaskId) {
    debugLog("mt-sync", {
      phase: "task-execute-skip",
      mid, sid, tid,
      reason: "no mtTaskId in mapping",
    });
    return;
  }

  const result = mtCliTasksClaim(basePath, mtTaskId);
  if (!result.ok) {
    debugLog("mt-sync", {
      phase: "task-claim-failed",
      mid, sid, tid, mtTaskId,
      error: result.error,
    });
    return;
  }

  setTaskRecord(mapping, mid, sid, tid, {
    mtTaskId,
    state: "claimed",
    lastSyncedAt: new Date().toISOString(),
  });

  debugLog("mt-sync", { phase: "task-claimed", mid, sid, tid, mtTaskId });
}

/**
 * Sync when a task is completed вҖ” mark complete in Milestone Tracker.
 */
async function syncTaskComplete(basePath, mapping, mid, sid, tid) {
  const existing = getTaskRecord(mapping, mid, sid, tid);
  if (existing?.state === "completed") return;

  const mtTaskId = existing?.mtTaskId ?? getMtTaskId(mapping, mid, sid, tid);

  if (!mtTaskId) {
    debugLog("mt-sync", {
      phase: "task-complete-skip",
      mid, sid, tid,
      reason: "no mtTaskId in mapping",
    });
    return;
  }

  const result = mtCliTasksComplete(basePath, mtTaskId, {
    message: `GSD task ${mid}/${sid}/${tid} completed`,
  });

  if (!result.ok) {
    debugLog("mt-sync", {
      phase: "task-complete-failed",
      mid, sid, tid, mtTaskId,
      error: result.error,
    });
    return;
  }

  setTaskRecord(mapping, mid, sid, tid, {
    mtTaskId,
    state: "completed",
    lastSyncedAt: new Date().toISOString(),
  });

  debugLog("mt-sync", { phase: "task-completed", mid, sid, tid, mtTaskId });
}

/**
 * Sync when a slice is completed вҖ” mark all mapped tasks complete.
 */
async function syncSliceComplete(basePath, mapping, mid, sid) {
  const sliceRecord = getSliceRecord(mapping, mid, sid);
  if (!sliceRecord || sliceRecord.state === "completed") return;

  // Complete any outstanding tasks in this slice
  const taskPrefix = `${mid}/${sid}/`;
  for (const [key, record] of Object.entries(mapping.tasks)) {
    if (!key.startsWith(taskPrefix)) continue;
    if (record.state === "completed") continue;

    const mtTaskId = record.mtTaskId;
    if (!mtTaskId) continue;

    const result = mtCliTasksComplete(basePath, mtTaskId, {
      message: `GSD slice ${mid}/${sid} completed`,
    });

    if (result.ok) {
      record.state = "completed";
      record.lastSyncedAt = new Date().toISOString();
    } else {
      debugLog("mt-sync", {
        phase: "slice-complete-task-failed",
        mid, sid, tid: key.split("/")[2],
        mtTaskId,
        error: result.error,
      });
    }
  }

  sliceRecord.state = "completed";
  sliceRecord.lastSyncedAt = new Date().toISOString();
  setSliceRecord(mapping, mid, sid, sliceRecord);

  debugLog("mt-sync", { phase: "slice-completed", mid, sid });
}

// в”Җв”Җв”Җ Bootstrap в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

/**
 * Walk the `.gsd/milestones/` tree and create mapping entries for
 * existing milestones/slices/tasks. Does NOT create tasks in Milestone
 * Tracker (that requires manual mapping or auto-creation in a future
 * iteration). Safe to run multiple times вҖ” idempotent.
 *
 * @param {string} basePath - Project root path
 * @returns {{ milestones: number, slices: number, tasks: number }}
 */
export async function bootstrapSync(basePath) {
  if (!mtCliIsAvailable()) {
    debugLog("mt-sync", { skip: "mt-cli not available", phase: "bootstrap" });
    return { milestones: 0, slices: 0, tasks: 0 };
  }

  // Check connectivity
  const statusResult = mtCliStatus(basePath);
  if (!statusResult.ok) {
    debugLog("mt-sync", { phase: "bootstrap-status-failed", error: statusResult.error });
    return { milestones: 0, slices: 0, tasks: 0 };
  }

  debugLog("mt-sync", { phase: "bootstrap-start", server: statusResult.data });

  const milestonesDir = join(basePath, ".gsd", "milestones");
  if (!existsSync(milestonesDir)) {
    return { milestones: 0, slices: 0, tasks: 0 };
  }

  const counts = { milestones: 0, slices: 0, tasks: 0 };

  const milestoneIds = readdirSync(milestonesDir, { withFileTypes: true })
    .filter((d) => d.isDirectory())
    .map((d) => d.name)
    .sort();

  for (const mid of milestoneIds) {
    let mapping = loadSyncMapping(basePath);
    if (!mapping) {
      mapping = createEmptyMapping(mid);
    }

    counts.milestones++;

    const slicesDir = join(milestonesDir, mid, "slices");
    if (!existsSync(slicesDir)) {
      saveSyncMapping(basePath, mapping);
      continue;
    }

    const sliceIds = readdirSync(slicesDir, { withFileTypes: true })
      .filter((d) => d.isDirectory())
      .map((d) => d.name)
      .sort();

    for (const sid of sliceIds) {
      if (!getSliceRecord(mapping, mid, sid)) {
        setSliceRecord(mapping, mid, sid, {
          syncedAt: new Date().toISOString(),
          state: "planned",
        });
        counts.slices++;
      }

      // Walk tasks
      const tasksDir = join(slicesDir, sid, "tasks");
      if (!existsSync(tasksDir)) continue;

      const taskIds = readdirSync(tasksDir, { withFileTypes: true })
        .filter((d) => d.isDirectory())
        .map((d) => d.name)
        .sort();

      for (const tid of taskIds) {
        if (!getTaskRecord(mapping, mid, sid, tid)) {
          // Bootstrap creates mapping entries but does NOT auto-create
          // tasks in Milestone Tracker вҖ” that requires explicit mapping.
          setTaskRecord(mapping, mid, sid, tid, {
            mtTaskId: null,
            state: "unmapped",
            lastSyncedAt: new Date().toISOString(),
          });
          counts.tasks++;
        }
      }
    }

    saveSyncMapping(basePath, mapping);
  }

  debugLog("mt-sync", { phase: "bootstrap-complete", ...counts });
  return counts;
}

/**
 * Get the current sync status summary.
 * @param {string} basePath
 * @returns {object|null}
 */
export function getSyncStatus(basePath) {
  const mapping = loadSyncMapping(basePath);
  if (!mapping) return null;

  const slices = Object.values(mapping.slices);
  const tasks = Object.values(mapping.tasks);

  return {
    milestoneId: mapping.milestoneId,
    slicesTotal: slices.length,
    slicesCompleted: slices.filter((s) => s.state === "completed").length,
    tasksTotal: tasks.length,
    tasksMapped: tasks.filter((t) => t.mtTaskId).length,
    tasksCompleted: tasks.filter((t) => t.state === "completed").length,
    tasksUnmapped: tasks.filter((t) => !t.mtTaskId).length,
    lastTaskSync: tasks.length > 0
      ? tasks.reduce((latest, t) => {
          const ts = t.lastSyncedAt || t.syncedAt || "";
          return ts > latest ? ts : latest;
        }, "")
      : null,
  };
}

/**
 * Thin wrapper around the `mt-cli` CLI binary.
 *
 * Every public function returns `MtResult<T>` вҖ” never throws.
 * Uses `execFileSync` (not `execSync`) for safety.
 *
 * Architecture follows the github-sync/cli.js pattern.
 */
import { execFileSync } from "node:child_process";

// в”Җв”Җв”Җ Result Type в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

function ok(data) {
  return { ok: true, data };
}

function fail(error) {
  return { ok: false, error };
}

// в”Җв”Җв”Җ mt-cli Availability в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

let _mtCliAvailable = null;

/**
 * Check whether the `mt-cli` binary is available on PATH.
 * Result is cached for the lifetime of the process.
 */
export function mtCliIsAvailable() {
  if (_mtCliAvailable !== null) return _mtCliAvailable;
  try {
    execFileSync("mt-cli", ["--version"], {
      encoding: "utf-8",
      stdio: ["ignore", "pipe", "ignore"],
      timeout: 5_000,
    });
    _mtCliAvailable = true;
  } catch {
    _mtCliAvailable = false;
  }
  return _mtCliAvailable;
}

/** Reset cached availability (for testing). */
export function _resetMtCliCache() {
  _mtCliAvailable = null;
}

// в”Җв”Җв”Җ Helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

const MT_CLI_TIMEOUT = 30_000;

/**
 * Run an mt-cli command and return the raw stdout as a string.
 * Returns `MtResult<string>` вҖ” never throws.
 */
function runMtCli(args, cwd) {
  try {
    const stdout = execFileSync("mt-cli", args, {
      cwd,
      encoding: "utf-8",
      stdio: ["ignore", "pipe", "pipe"],
      timeout: MT_CLI_TIMEOUT,
    }).trim();
    return ok(stdout);
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    return fail(msg);
  }
}

/**
 * Run an mt-cli command with `--json` and parse the output.
 * Returns `MtResult<object>` вҖ” never throws.
 */
function runMtCliJson(args, cwd) {
  const result = runMtCli([...args, "--json"], cwd);
  if (!result.ok) return fail(result.error);
  try {
    return ok(JSON.parse(result.data));
  } catch {
    return fail(`Failed to parse JSON from mt-cli: ${result.data.slice(0, 200)}`);
  }
}

// в”Җв”Җв”Җ Status / Bootstrap в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

/**
 * Check mt-cli server connectivity and config.
 * Returns `MtResult<object>` with serverUrl, milestoneId, connected, etc.
 */
export function mtCliStatus(cwd) {
  return runMtCliJson(["status"], cwd);
}

/**
 * List tasks from the Milestone Tracker.
 * Returns `MtResult<object[]>` with task records.
 */
export function mtCliTasksList(cwd, opts = {}) {
  const args = ["tasks", "list"];
  if (opts.status) {
    args.push("--status", opts.status);
  }
  return runMtCliJson(args, cwd);
}

// в”Җв”Җв”Җ Task Lifecycle Commands в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

/**
 * Claim a task for an agent.
 * @param {string} cwd - Working directory
 * @param {string} taskId - mt-cli task ID (short or full)
 * @param {object} opts - { agent?: string }
 * @returns {MtResult<object>} - Claimed task record
 */
export function mtCliTasksClaim(cwd, taskId, opts = {}) {
  const args = ["tasks", "claim", taskId];
  if (opts.agent) {
    args.push("--agent", opts.agent);
  }
  return runMtCliJson(args, cwd);
}

/**
 * Update task progress.
 * @param {string} cwd
 * @param {string} taskId
 * @param {object} opts - { subTotal?, subDone?, message? }
 * @returns {MtResult<object>}
 */
export function mtCliTasksProgress(cwd, taskId, opts = {}) {
  const args = ["tasks", "progress", taskId];
  if (opts.subTotal !== undefined) {
    args.push("--sub-total", String(opts.subTotal));
  }
  if (opts.subDone !== undefined) {
    args.push("--sub-done", String(opts.subDone));
  }
  if (opts.message) {
    args.push("--message", opts.message);
  }
  return runMtCliJson(args, cwd);
}

/**
 * Block a task with a reason.
 * @param {string} cwd
 * @param {string} taskId
 * @param {string} reason - Required block reason
 * @returns {MtResult<object>}
 */
export function mtCliTasksBlock(cwd, taskId, reason) {
  const args = ["tasks", "block", taskId, "--reason", reason];
  return runMtCliJson(args, cwd);
}

/**
 * Unblock a task with an optional message.
 * @param {string} cwd
 * @param {string} taskId
 * @param {object} opts - { message? }
 * @returns {MtResult<object>}
 */
export function mtCliTasksUnblock(cwd, taskId, opts = {}) {
  const args = ["tasks", "unblock", taskId];
  if (opts.message) {
    args.push("--message", opts.message);
  }
  return runMtCliJson(args, cwd);
}

/**
 * Complete a task with optional evidence.
 * @param {string} cwd
 * @param {string} taskId
 * @param {object} opts - { message?, evidence?, filesTouched? }
 * @returns {MtResult<object>}
 */
export function mtCliTasksComplete(cwd, taskId, opts = {}) {
  const args = ["tasks", "complete", taskId];
  if (opts.message) {
    args.push("--message", opts.message);
  }
  if (opts.evidence) {
    args.push("--evidence", JSON.stringify(opts.evidence));
  }
  if (opts.filesTouched) {
    args.push("--files-touched", JSON.stringify(opts.filesTouched));
  }
  return runMtCliJson(args, cwd);
}

/**
 * Persistence layer for the mt-cli sync mapping.
 *
 * The mapping lives at `.gsd/mt-sync.json` and tracks which GSD
 * entities (milestones, slices, tasks) have been synced to the
 * Milestone Tracker via mt-cli, along with sync timestamps and status.
 *
 * Architecture follows the github-sync extension pattern.
 */
import { existsSync, readFileSync, writeFileSync, renameSync, mkdirSync, unlinkSync } from "node:fs";
import { join, dirname } from "node:path";
import { randomBytes } from "node:crypto";

const MAPPING_FILENAME = "mt-sync.json";

function mappingPath(basePath) {
  return join(basePath, ".gsd", MAPPING_FILENAME);
}

// в”Җв”Җв”Җ Local atomic write (avoids dependency on gsd/atomic-write.js) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

/**
 * Simple atomic write: write to temp file then rename.
 * Safe for single-process use (which is all we need for this extension).
 */
function atomicWriteSync(filePath, content) {
  mkdirSync(dirname(filePath), { recursive: true });
  const tmpPath = filePath + `.tmp.${randomBytes(4).toString("hex")}`;
  writeFileSync(tmpPath, content, "utf-8");
  try {
    renameSync(tmpPath, filePath);
  } catch (err) {
    try { unlinkSync(tmpPath); } catch { /* best-effort cleanup */ }
    throw err;
  }
}

// в”Җв”Җв”Җ Load / Save в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

/**
 * Load the sync mapping from disk.
 * Returns null if the file doesn't exist, is corrupt, or has the wrong version.
 */
export function loadSyncMapping(basePath) {
  const path = mappingPath(basePath);
  if (!existsSync(path)) return null;
  try {
    const raw = readFileSync(path, "utf-8");
    const parsed = JSON.parse(raw);
    if (parsed?.version !== 1) return null;
    return parsed;
  } catch {
    return null;
  }
}

/**
 * Save the sync mapping to disk atomically.
 */
export function saveSyncMapping(basePath, mapping) {
  const path = mappingPath(basePath);
  atomicWriteSync(path, JSON.stringify(mapping, null, 2) + "\n");
}

/**
 * Create an empty sync mapping for a given milestone ID.
 */
export function createEmptyMapping(milestoneId) {
  return {
    version: 1,
    milestoneId,
    slices: {},
    tasks: {},
  };
}

// в”Җв”Җв”Җ Accessors в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

/**
 * Get the record for a slice, or null if not synced.
 */
export function getSliceRecord(mapping, mid, sid) {
  return mapping.slices[`${mid}/${sid}`] ?? null;
}

/**
 * Get the record for a task, or null if not synced.
 */
export function getTaskRecord(mapping, mid, sid, tid) {
  return mapping.tasks[`${mid}/${sid}/${tid}`] ?? null;
}

/**
 * Get the mt-cli task ID for a GSD task, or null if not mapped.
 */
export function getMtTaskId(mapping, mid, sid, tid) {
  const record = getTaskRecord(mapping, mid, sid, tid);
  return record?.mtTaskId ?? null;
}

// в”Җв”Җв”Җ Mutators в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

/**
 * Set (create or update) the record for a slice.
 */
export function setSliceRecord(mapping, mid, sid, record) {
  mapping.slices[`${mid}/${sid}`] = record;
}

/**
 * Set (create or update) the record for a task.
 */
export function setTaskRecord(mapping, mid, sid, tid, record) {
  mapping.tasks[`${mid}/${sid}/${tid}`] = record;
}

